  1→import React, { useRef, useEffect, useCallback, useMemo } from 'react';
  2→import { Layer, Shape, Text, Line } from 'react-konva';
  3→import { STAR_COLORS } from '../utils/starUtils';
  4→
  5→const parseHex = (hex) => ({
  6→    r: parseInt(hex.slice(1, 3), 16),
  7→    g: parseInt(hex.slice(3, 5), 16),
  8→    b: parseInt(hex.slice(5, 7), 16),
  9→});
 10→
 11→const ConstellationLayer = React.memo(({ layerProps, constellations, computedStarPositions, zoom, chainColors, userId, onConstellationFocus, focusedConstellationId }) => {
 12→    const shapeRef = useRef(null);
 13→    const animRef = useRef({ time: 0, raf: null });
 14→    const focusIdRef = useRef(focusedConstellationId);
 15→    focusIdRef.current = focusedConstellationId;
 16→    const resolvedLinksRef = useRef([]);
 17→
 18→    const linkData = useMemo(() => {
 19→        if (!Array.isArray(constellations) || constellations.length === 0) return [];
 20→        return constellations.map((link, i) => {
 21→            const colorHex = chainColors?.get(link.id) || STAR_COLORS[i % STAR_COLORS.length];
 22→            const rgb = parseHex(colorHex);
 23→            const isPending = link.status === 'pending';
 24→            const isDeclined = link.status === 'declined';
 25→            const isOwnPending = isPending && (link.user_id_a === userId || link.user_id_b === userId);
 26→            return { ...link, rgb, colorHex, isPending, isDeclined, isOwnPending };
 27→        });
 28→    }, [constellations, chainColors, userId]);
 29→
 30→    // Resolve positions for each link
 31→    const resolvedLinks = useMemo(() => {
 32→        return linkData
 33→            .filter(link => !link.isDeclined)
 34→            .filter(link => !link.isPending || link.isOwnPending)
 35→            .map(link => {
 36→                const posA = computedStarPositions.get(link.star_id_a)
 37→                    || (link.a_universe_x != null ? { x: link.a_universe_x, y: link.a_universe_y } : null);
 38→                const posB = computedStarPositions.get(link.star_id_b)
 39→                    || (link.b_universe_x != null ? { x: link.b_universe_x, y: link.b_universe_y } : null);
 40→                if (!posA || !posB) return null;
 41→                return { ...link, ax: posA.x, ay: posA.y, bx: posB.x, by: posB.y };
 42→            })
 43→            .filter(Boolean);
 44→    }, [linkData, computedStarPositions]);
 45→    resolvedLinksRef.current = resolvedLinks;
 46→
 47→    const animate = useCallback(() => {
 48→        animRef.current.time = performance.now();
 49→        const node = shapeRef.current;
 50→        if (node) {
 51→            const layer = node.getLayer();
 52→            if (layer) layer.batchDraw();
 53→        }
 54→        animRef.current.raf = requestAnimationFrame(animate);
 55→    }, []);
 56→
 57→    useEffect(() => {
 58→        const hasAccepted = resolvedLinks.some(l => !l.isPending);
 59→        if (!hasAccepted) return;
 60→        animRef.current.raf = requestAnimationFrame(animate);
 61→        return () => {
 62→            if (animRef.current.raf) cancelAnimationFrame(animRef.current.raf);
 63→        };
 64→    }, [animate, resolvedLinks]);
 65→
 66→    if (resolvedLinks.length === 0) return null;
 67→
 68→    // Separate labels for Konva Text nodes (need scaleX/scaleY zoom correction)
 69→    const labels = resolvedLinks.filter(l => !l.isPending && l.label);
 70→
 71→    return (
 72→        <Layer {...layerProps}>
 73→            <Shape
 74→                ref={shapeRef}
 75→                sceneFunc={(ctx) => {
 76→                    const time = animRef.current.time || performance.now();
 77→                    const currentFocusId = focusIdRef.current;
 78→                    const hasFocus = currentFocusId != null;
 79→                    const links = resolvedLinksRef.current;
 80→
 81→                    for (const link of links) {
 82→                        const { ax, ay, bx, by, rgb } = link;
 83→                        const isFocusedLine = hasFocus && link.id === currentFocusId;
 84→                        const isDimmedLine = hasFocus && !isFocusedLine;
 85→
 86→                        if (link.isPending) {
 87→                            ctx.save();
 88→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},${isDimmedLine ? 0.01 : 0.08})`;
 89→                            ctx.lineWidth = 1;
 90→                            ctx.setLineDash([5, 10]);
 91→                            ctx.lineCap = 'round';
 92→                            ctx.beginPath();
 93→                            ctx.moveTo(ax, ay);
 94→                            ctx.lineTo(bx, by);
 95→                            ctx.stroke();
 96→                            ctx.restore();
 97→                            continue;
 98→                        }
 99→
100→                        if (isFocusedLine) {
101→                            // Focused: extra-wide outer glow
102→                            ctx.save();
103→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.12)`;
104→                            ctx.lineWidth = 18;
105→                            ctx.lineCap = 'round';
106→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.7)`;
107→                            ctx.shadowBlur = 40;
108→                            ctx.setLineDash([]);
109→                            ctx.beginPath();
110→                            ctx.moveTo(ax, ay);
111→                            ctx.lineTo(bx, by);
112→                            ctx.stroke();
113→                            ctx.restore();
114→
115→                            // Focused: bright underglow
116→                            ctx.save();
117→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.25)`;
118→                            ctx.lineWidth = 8;
119→                            ctx.lineCap = 'round';
120→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.5)`;
121→                            ctx.shadowBlur = 24;
122→                            ctx.setLineDash([]);
123→                            ctx.beginPath();
124→                            ctx.moveTo(ax, ay);
125→                            ctx.lineTo(bx, by);
126→                            ctx.stroke();
127→                            ctx.restore();
128→
129→                            // Focused: solid body
130→                            ctx.save();
131→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.5)`;
132→                            ctx.lineWidth = 3;
133→                            ctx.lineCap = 'round';
134→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.6)`;
135→                            ctx.shadowBlur = 12;
136→                            ctx.setLineDash([]);
137→                            ctx.beginPath();
138→                            ctx.moveTo(ax, ay);
139→                            ctx.lineTo(bx, by);
140→                            ctx.stroke();
141→                            ctx.restore();
142→
143→                            // Focused: bright animated core
144→                            ctx.save();
145→                            ctx.strokeStyle = `rgba(255,255,255,0.8)`;
146→                            ctx.lineWidth = 1.5;
147→                            ctx.lineCap = 'round';
148→                            ctx.setLineDash([14, 10]);
149→                            ctx.lineDashOffset = time * 0.04;
150→                            ctx.beginPath();
151→                            ctx.moveTo(ax, ay);
152→                            ctx.lineTo(bx, by);
153→                            ctx.stroke();
154→                            ctx.restore();
155→                        } else if (isDimmedLine) {
156→                            // Dimmed: nearly invisible
157→                            ctx.save();
158→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.02)`;
159→                            ctx.lineWidth = 3;
160→                            ctx.lineCap = 'round';
161→                            ctx.setLineDash([]);
162→                            ctx.beginPath();
163→                            ctx.moveTo(ax, ay);
164→                            ctx.lineTo(bx, by);
165→                            ctx.stroke();
166→                            ctx.restore();
167→                        } else {
168→                            // Normal: triple-layer glow
169→
170→                            // Layer 1: Wide underglow
171→                            ctx.save();
172→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.06)`;
173→                            ctx.lineWidth = 8;
174→                            ctx.lineCap = 'round';
175→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.3)`;
176→                            ctx.shadowBlur = 20;
177→                            ctx.setLineDash([]);
178→                            ctx.beginPath();
179→                            ctx.moveTo(ax, ay);
180→                            ctx.lineTo(bx, by);
181→                            ctx.stroke();
182→                            ctx.restore();
183→
184→                            // Layer 2: Medium body
185→                            ctx.save();
186→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.12)`;
187→                            ctx.lineWidth = 3;
188→                            ctx.lineCap = 'round';
189→                            ctx.shadowColor = `rgba(${rgb.r},${rgb.g},${rgb.b},0.3)`;
190→                            ctx.shadowBlur = 8;
191→                            ctx.setLineDash([]);
192→                            ctx.beginPath();
193→                            ctx.moveTo(ax, ay);
194→                            ctx.lineTo(bx, by);
195→                            ctx.stroke();
196→                            ctx.restore();
197→
198→                            // Layer 3: Thin animated core
199→                            ctx.save();
200→                            ctx.strokeStyle = `rgba(${rgb.r},${rgb.g},${rgb.b},0.45)`;
201→                            ctx.lineWidth = 1.2;
202→                            ctx.lineCap = 'round';
203→                            ctx.setLineDash([14, 10]);
204→                            ctx.lineDashOffset = time * 0.04;
205→                            ctx.beginPath();
206→                            ctx.moveTo(ax, ay);
207→                            ctx.lineTo(bx, by);
208→                            ctx.stroke();
209→                            ctx.restore();
210→                        }
211→                    }
212→                }}
213→                perfectDrawEnabled={false}
214→                listening={false}
215→            />
216→            {/* Labels rendered as Konva Text for zoom correction */}
217→            {labels.map((link) => {
218→                const mx = (link.ax + link.bx) / 2;
219→                const my = (link.ay + link.by) / 2;
220→                return (
221→                    <Text
222→                        key={`label-${link.id}`}
223→                        x={mx}
224→                        y={my - 14}
225→                        text={link.label}
226→                        fontSize={12}
227→                        fontFamily="sans-serif"
228→                        fill={`rgba(${link.rgb.r},${link.rgb.g},${link.rgb.b},0.7)`}
229→                        align="center"
230→                        offsetX={link.label.length * 3}
231→                        scaleX={1 / zoom}
232→                        scaleY={1 / zoom}
233→                        listening={false}
234→                        perfectDrawEnabled={false}
235→                    />
236→                );
237→            })}
238→            {/* Invisible hit detection lines for accepted constellations */}
239→            {resolvedLinks.filter(l => !l.isPending).map((link) => (
240→                <Line
241→                    key={`hit-${link.id}`}
242→                    points={[link.ax, link.ay, link.bx, link.by]}
243→                    stroke="transparent"
244→                    strokeWidth={1}
245→                    hitStrokeWidth={20 / zoom}
246→                    onClick={() => onConstellationFocus?.(link)}
247→                    onTap={() => onConstellationFocus?.(link)}
248→                    perfectDrawEnabled={false}
249→                />
250→            ))}
251→        </Layer>
252→    );
253→});
254→
255→ConstellationLayer.displayName = 'ConstellationLayer';
256→
257→export default ConstellationLayer;
