516→export const computeSemanticBridges = (
517→    posts,
518→    computedStarPositions,
519→    threshold = 0.9,
520→    maxPairs = 120
521→) => {
522→    if (!Array.isArray(posts) || posts.length < 2) return [];
523→    if (!(computedStarPositions instanceof Map)) return [];
524→
525→    const minSimilarity = Number.isFinite(Number(threshold)) ? Number(threshold) : 0.9;
526→    const limit = normalizeMaxEdges(maxPairs, 120);
527→
528→    const enriched = [];
529→    for (const post of posts) {
530→        const postId = post?.id;
531→        if (!postId || !computedStarPositions.has(postId)) continue;
532→        const embedding = normalizeEmbedding(post?.embeddings);
533→        if (!embedding) continue;
534→        enriched.push({ postId, embedding });
535→    }
536→
537→    if (enriched.length < 2) return [];
538→
539→    const pairs = [];
540→    for (let i = 0; i < enriched.length; i++) {
541→        for (let j = i + 1; j < enriched.length; j++) {
542→            const similarity = cosineSimilarity(enriched[i].embedding, enriched[j].embedding);
543→            if (similarity > minSimilarity) {
544→                pairs.push({
545→                    post_a: enriched[i].postId,
546→                    post_b: enriched[j].postId,
547→                    similarity,
548→                });
549→            }
550→        }
551→    }
552→
553→    pairs.sort((a, b) => b.similarity - a.similarity);
554→    return pairs.length > limit ? pairs.slice(0, limit) : pairs;
555→};
