  1→import { mulberry32 } from './proceduralGeneration';
  2→import { simpleHash, hexToRgba } from './starUtils';
  3→
  4→// Parse hex color to {r, g, b}
  5→const hexToRgb = (hex) => ({
  6→    r: parseInt(hex.slice(1, 3), 16),
  7→    g: parseInt(hex.slice(3, 5), 16),
  8→    b: parseInt(hex.slice(5, 7), 16),
  9→});
 10→
 11→// Lerp between two {r,g,b} objects
 12→const lerpColor = (a, b, t) => ({
 13→    r: Math.round(a.r + (b.r - a.r) * t),
 14→    g: Math.round(a.g + (b.g - a.g) * t),
 15→    b: Math.round(a.b + (b.b - a.b) * t),
 16→});
 17→
 18→const WARM = hexToRgb('#ffd7a0');
 19→const COOL = hexToRgb('#4a7fff');
 20→
 21→/**
 22→ * Generate deterministic spiral galaxy data for a user.
 23→ * All positions are relative to (0,0) — caller offsets by galaxy center.
 24→ */
 25→export const generateGalaxyData = (userId) => {
 26→    const seed = simpleHash(userId) + 7919;
 27→    const rng = mulberry32(seed);
 28→
 29→    const armCount = 2 + Math.floor(rng() * 3); // 2-4
 30→    const rotation = rng() * Math.PI * 2;
 31→    const axialTilt = 0.45 + rng() * 0.3; // 0.45-0.75
 32→    const winding = 2.5 + rng() * 1.5; // 2.5-4.0
 33→    const galaxyRadius = 250 + rng() * 100; // 250-350
 34→    const coreSize = 0.18 + rng() * 0.1; // 0.18-0.28
 35→    const coreRadius = galaxyRadius * coreSize;
 36→
 37→    // Pre-compute arm particles
 38→    const particleCount = 300;
 39→    const particles = new Array(particleCount);
 40→
 41→    for (let i = 0; i < particleCount; i++) {
 42→        const armIndex = i % armCount;
 43→        const t = rng() * winding;
 44→        const progress = t / winding; // 0 = core, 1 = outer edge
 45→
 46→        // Archimedean spiral
 47→        const r = coreRadius + (galaxyRadius - coreRadius) * progress;
 48→        const theta = t + (armIndex / armCount) * Math.PI * 2 + rotation;
 49→
 50→        // Scatter perpendicular to arm — wider at outer edges
 51→        const spread = 8 + progress * 35;
 52→        const scatter = (rng() - 0.5) * 2 * spread;
 53→        const tangentAngle = theta + Math.PI / 2;
 54→
 55→        const x = r * Math.cos(theta) + scatter * Math.cos(tangentAngle);
 56→        const y = (r * Math.sin(theta) + scatter * Math.sin(tangentAngle)) * axialTilt;
 57→
 58→        const dotRadius = 0.6 + rng() * 1.8;
 59→        const alpha = 0.15 + rng() * 0.45;
 60→
 61→        particles[i] = { x, y, radius: dotRadius, progress, alpha };
 62→    }
 63→
 64→    // Pre-compute arm curve polylines for glow strokes
 65→    const armCurves = [];
 66→    const curveSteps = 40;
 67→    for (let a = 0; a < armCount; a++) {
 68→        const points = new Array(curveSteps);
 69→        for (let s = 0; s < curveSteps; s++) {
 70→            const t = (s / (curveSteps - 1)) * winding;
 71→            const r = coreRadius + (galaxyRadius - coreRadius) * (t / winding);
 72→            const theta = t + (a / armCount) * Math.PI * 2 + rotation;
 73→            points[s] = {
 74→                x: r * Math.cos(theta),
 75→                y: r * Math.sin(theta) * axialTilt,
 76→            };
 77→        }
 78→        armCurves.push(points);
 79→    }
 80→
 81→    return { galaxyRadius, coreRadius, axialTilt, particles, armCurves };
 82→};
 83→
 84→/**
 85→ * Draw all galaxy visuals + connection lines onto a single canvas context.
 86→ * Each entry in `galaxies` must have: x, y, color, galaxyRadius, coreRadius, particles, armCurves.
 87→ * Optional `edges` array: [{user_a, user_b, similarity}] for similarity-based connections.
 88→ * Optional `galaxyUserIdMap`: Map<userId, galaxyIndex> for edge lookups.
 89→ */
 90→export const drawGalaxyVisuals = (ctx, galaxies, edges, galaxyUserIdMap) => {
 91→    if (!galaxies || galaxies.length === 0) return;
 92→
 93→    // --- Draw each galaxy ---
 94→    for (let g = 0; g < galaxies.length; g++) {
 95→        const gal = galaxies[g];
 96→        const { x: cx, y: cy, color, galaxyRadius, coreRadius, particles, armCurves } = gal;
 97→        const accent = hexToRgb(color);
 98→
 99→        // 1. Outer halo
100→        const haloGrad = ctx.createRadialGradient(cx, cy, coreRadius, cx, cy, galaxyRadius * 1.2);
101→        haloGrad.addColorStop(0, hexToRgba(color, 0.08));
102→        haloGrad.addColorStop(0.6, hexToRgba(color, 0.03));
103→        haloGrad.addColorStop(1, 'rgba(0,0,0,0)');
104→        ctx.fillStyle = haloGrad;
105→        ctx.beginPath();
106→        ctx.arc(cx, cy, galaxyRadius * 1.2, 0, Math.PI * 2);
107→        ctx.fill();
108→
109→        // 2. Arm particles
110→        for (let i = 0; i < particles.length; i++) {
111→            const p = particles[i];
112→            // Color: inner = warm lerp with accent, outer = cool lerp with accent
113→            let c;
114→            if (p.progress < 0.5) {
115→                const t = p.progress / 0.5;
116→                c = lerpColor(WARM, accent, t);
117→            } else {
118→                const t = (p.progress - 0.5) / 0.5;
119→                c = lerpColor(accent, COOL, t);
120→            }
121→            ctx.fillStyle = `rgba(${c.r},${c.g},${c.b},${p.alpha})`;
122→            ctx.beginPath();
123→            ctx.arc(cx + p.x, cy + p.y, p.radius, 0, Math.PI * 2);
124→            ctx.fill();
125→        }
126→
127→        // 3. Arm glow lines
128→        ctx.strokeStyle = hexToRgba(color, 0.08);
129→        ctx.lineWidth = 1.5;
130→        for (let a = 0; a < armCurves.length; a++) {
131→            const pts = armCurves[a];
132→            ctx.beginPath();
133→            ctx.moveTo(cx + pts[0].x, cy + pts[0].y);
134→            for (let s = 1; s < pts.length; s++) {
135→                ctx.lineTo(cx + pts[s].x, cy + pts[s].y);
136→            }
137→            ctx.stroke();
138→        }
139→
140→        // 4. Core glow — multi-stop radial gradient
141→        const coreGrad = ctx.createRadialGradient(cx, cy, 0, cx, cy, coreRadius * 2);
142→        coreGrad.addColorStop(0, 'rgba(255,255,255,0.9)');
143→        coreGrad.addColorStop(0.15, 'rgba(255,248,220,0.6)');
144→        coreGrad.addColorStop(0.5, hexToRgba(color, 0.3));
145→        coreGrad.addColorStop(1, 'rgba(0,0,0,0)');
146→        ctx.fillStyle = coreGrad;
147→        ctx.beginPath();
148→        ctx.arc(cx, cy, coreRadius * 2, 0, Math.PI * 2);
149→        ctx.fill();
150→    }
151→
152→    // --- Connection lines ---
153→    if (edges && edges.length > 0 && galaxyUserIdMap) {
154→        // Similarity-based connections from galaxy_edges
155→        for (const edge of edges) {
156→            const idxA = galaxyUserIdMap.get(edge.user_a);
157→            const idxB = galaxyUserIdMap.get(edge.user_b);
158→            if (idxA == null || idxB == null) continue;
159→
160→            const a = galaxies[idxA];
161→            const b = galaxies[idxB];
162→            const dx = b.x - a.x;
163→            const dy = b.y - a.y;
164→            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
165→
166→            // Opacity and width scale with similarity
167→            const opacity = 0.04 + edge.similarity * 0.08;
168→            const width = 0.3 + edge.similarity * 0.7;
169→
170→            const mx = (a.x + b.x) / 2;
171→            const my = (a.y + b.y) / 2;
172→            const perpX = -dy / dist * dist * 0.08;
173→            const perpY = dx / dist * dist * 0.08;
174→
175→            ctx.strokeStyle = `rgba(150,200,255,${opacity})`;
176→            ctx.lineWidth = width;
177→            ctx.beginPath();
178→            ctx.moveTo(a.x, a.y);
179→            ctx.quadraticCurveTo(mx + perpX, my + perpY, b.x, b.y);
180→            ctx.stroke();
181→        }
182→    } else {
183→        // Fallback: distance-based connections
184→        const MAX_DIST = 5000;
185→        const MAX_DIST_SQ = MAX_DIST * MAX_DIST;
186→
187→        for (let i = 0; i < galaxies.length; i++) {
188→            for (let j = i + 1; j < galaxies.length; j++) {
189→                const a = galaxies[i];
190→                const b = galaxies[j];
191→                const dx = b.x - a.x;
192→                const dy = b.y - a.y;
193→                const distSq = dx * dx + dy * dy;
194→                if (distSq > MAX_DIST_SQ) continue;
195→
196→                const dist = Math.sqrt(distSq);
197→                const fade = 1 - dist / MAX_DIST;
198→                const opacity = 0.06 * fade;
199→
200→                const mx = (a.x + b.x) / 2;
201→                const my = (a.y + b.y) / 2;
202→                const perpX = -dy / dist * dist * 0.1;
203→                const perpY = dx / dist * dist * 0.1;
204→
205→                ctx.strokeStyle = `rgba(255,255,255,${opacity})`;
206→                ctx.lineWidth = 0.5;
207→                ctx.beginPath();
208→                ctx.moveTo(a.x, a.y);
209→                ctx.quadraticCurveTo(mx + perpX, my + perpY, b.x, b.y);
210→                ctx.stroke();
211→            }
212→        }
213→    }
214→};
