  6→const StarGroup = React.memo(({ x, y, radius, color, title, showTitle, isPulsing, onClick, onPointerDown, constellationColor, isFocused, isDimmed }) => {
  7→    const r = radius;
  8→    const groupRef = useRef(null);
  9→    const tweenRef = useRef(null);
 10→
 11→    useEffect(() => {
 12→        const node = groupRef.current;
 13→        if (!node) return;
 14→
 15→        // Cleanup any running tween
 16→        if (tweenRef.current) {
 17→            tweenRef.current.destroy();
 18→            tweenRef.current = null;
 19→        }
 20→
 21→        if (isPulsing) {
 22→            // Phase 1: elastic scale up 1 → 1.8
 23→            const tweenUp = new Konva.Tween({
 24→                node,
 25→                scaleX: 1.8,
 26→                scaleY: 1.8,
 27→                duration: 0.35,
 28→                easing: Konva.Easings.ElasticEaseOut,
 29→                onFinish: () => {
 30→                    // Phase 2: ease back down 1.8 → 1
 31→                    const tweenDown = new Konva.Tween({
 32→                        node,
 33→                        scaleX: 1,
 34→                        scaleY: 1,
 35→                        duration: 0.25,
 36→                        easing: Konva.Easings.EaseOut,
 37→                    });
 38→                    tweenRef.current = tweenDown;
 39→                    tweenDown.play();
 40→                },
 41→            });
 42→            tweenRef.current = tweenUp;
 43→            tweenUp.play();
 44→        } else {
 45→            // Reset to default scale
 46→            node.scaleX(1);
 47→            node.scaleY(1);
 48→        }
 49→
 50→        return () => {
 51→            if (tweenRef.current) {
 52→                tweenRef.current.destroy();
 53→                tweenRef.current = null;
 54→            }
 55→        };
 56→    }, [isPulsing]);
 57→
 58→    return (
 59→        <Group
 60→            ref={groupRef}
 61→            x={x}
 62→            y={y}
 63→            opacity={isDimmed ? 0.06 : 1}
 64→        >
 65→            {/* Extra wide glow when focused */}
 66→            {isFocused && (
 67→                <Circle
 68→                    radius={r * 5}
 69→                    fillRadialGradientStartPoint={{ x: 0, y: 0 }}
 70→                    fillRadialGradientEndPoint={{ x: 0, y: 0 }}
 71→                    fillRadialGradientStartRadius={0}
 72→                    fillRadialGradientEndRadius={r * 5}
 73→                    fillRadialGradientColorStops={[
 74→                        0, hexToRgba(color, 0.25),
 75→                        0.4, hexToRgba(color, 0.08),
 76→                        1, hexToRgba(color, 0),
 77→                    ]}
 78→                    perfectDrawEnabled={false}
 79→                    listening={false}
 80→                />
 81→            )}
 82→            {/* Outer atmosphere — shadow glow */}
 83→            <Circle
 84→                radius={r * 3}
 85→                fill="transparent"
 86→                shadowColor={color}
 87→                shadowBlur={isFocused ? r * 12 : r * 5}
 88→                shadowOpacity={1}
 89→                perfectDrawEnabled={false}
 90→                shadowForStrokeEnabled={false}
 91→                listening={false}
 92→            />
 93→            {/* Constellation membership ring */}
 94→            {constellationColor && (
 95→                <Circle
 96→                    radius={r * 2.8}
 97→                    stroke={constellationColor}
 98→                    strokeWidth={1.2}
 99→                    opacity={0.35}
100→                    dash={[4, 3]}
101→                    perfectDrawEnabled={false}
102→                    listening={false}
103→                />
104→            )}
105→            {/* Inner glow — radial gradient */}
106→            <Circle
107→                radius={r * 2.2}
108→                fillRadialGradientStartPoint={{ x: 0, y: 0 }}
109→                fillRadialGradientEndPoint={{ x: 0, y: 0 }}
110→                fillRadialGradientStartRadius={0}
111→                fillRadialGradientEndRadius={r * 2.2}
112→                fillRadialGradientColorStops={[
113→                    0, color,
114→                    0.4, hexToRgba(color, 0.65),
115→                    1, hexToRgba(color, 0),
116→                ]}
117→                perfectDrawEnabled={false}
118→                listening={false}
119→            />
120→            {/* Bright core */}
121→            <Circle
122→                radius={isFocused ? r * 0.6 : r * 0.5}
123→                fill="#ffffffee"
124→                shadowColor="#ffffff"
125→                shadowBlur={isFocused ? 10 : 4}
126→                shadowOpacity={1}
127→                perfectDrawEnabled={false}
128→                hitStrokeWidth={r + 12}
129→                onClick={onClick}
130→                onTap={onClick}
131→                onMouseDown={onPointerDown ? (e) => {
132→                    e.cancelBubble = true;
133→                    const screenX = e.evt.clientX;
134→                    const screenY = e.evt.clientY;
135→                    onPointerDown(screenX, screenY);
136→                } : undefined}
137→                onTouchStart={onPointerDown ? (e) => {
138→                    e.cancelBubble = true;
139→                    const touch = e.evt.touches?.[0];
140→                    if (touch) onPointerDown(touch.clientX, touch.clientY);
141→                } : undefined}
142→            />
143→            {showTitle && title && (
144→                <Text
145→                    text={title.length > 24 ? title.slice(0, 22) + '...' : title}
146→                    y={r * 2.2 + 4}
147→                    fontSize={10}
148→                    fill="rgba(255,255,255,0.6)"
149→                    align="center"
150→                    width={120}
151→                    offsetX={60}
152→                    listening={false}
153→                    perfectDrawEnabled={false}
154→                />
155→            )}
156→        </Group>
157→    );
158→});
