 40→GalaxyLabel.displayName = 'GalaxyLabel';
 41→
 42→const InteractiveLayer = React.memo(({
 43→    layerProps, posts, galaxies, zoom, showTitles, pulsingId,
 44→    onStarClick, onGalaxyClick,
 45→    galaxyPositions, starPullOffsets, similarPairs, galaxyEdges,
 46→    activePostIds, useEmbeddingBridges,
 47→    camera, stageSize,
 48→    computedStarPositions: computedStarPositionsProp,
 49→    constellationStarColors,
 50→    focusedStarIds,
 51→}) => {
 52→    // Build userId→index map for edge lookups in drawGalaxyVisuals
 53→    const galaxyUserIdMap = useMemo(() => {
 54→        const map = new Map();
 55→        galaxies?.forEach((g, i) => map.set(g.userId, i));
 56→        return map;
 57→    }, [galaxies]);
 58→
 59→    // Galaxy spiral visuals — positioned at animated galaxy coords
 60→    const galaxyVisuals = useMemo(() =>
 61→        galaxies?.map(g => ({
 62→            x: g.x,
 63→            y: g.y,
 64→            ...generateGalaxyData(g.userId),
 65→            color: getStarColor(g.userId),
 66→        })) || []
 67→    , [galaxies]);
 68→
 69→    // ── Compute every star's render position ─────────────────────────
 70→    // Use prop if provided (hoisted from Universe.jsx), otherwise compute locally.
 71→    const computedStarPositionsLocal = useMemo(() => {
 72→        if (computedStarPositionsProp) return computedStarPositionsProp;
 73→        const map = new Map();
 74→        for (const post of posts) {
 75→            const uid = post.users?.id ?? post.user_id;
 76→
 77→            const hashGal = userHomeCoords(uid);
 78→            const animGal = galaxyPositions?.get(uid);
 79→            const galDx = animGal ? (animGal.x - hashGal.x) : 0;
 80→            const galDy = animGal ? (animGal.y - hashGal.y) : 0;
 81→
 82→            const pull = starPullOffsets?.get(post.id);
 83→
 84→            const baseX = post.universe_x ?? post.display_x;
 85→            const baseY = post.universe_y ?? post.display_y;
 86→
 87→            map.set(post.id, {
 88→                x: baseX + galDx + (pull?.dx ?? 0),
 89→                y: baseY + galDy + (pull?.dy ?? 0),
 90→            });
 91→        }
 92→        return map;
 93→    }, [computedStarPositionsProp, posts, galaxyPositions, starPullOffsets]);
 94→    const computedStarPositions = computedStarPositionsLocal;
 95→
 96→    // ── Viewport culling: only render stars within visible bounds + buffer ──
 97→    const visibleBounds = useMemo(() => {
 98→        if (!camera || !stageSize || !zoom) return null;
 99→        const halfW = (stageSize.width / 2) / zoom;
100→        const halfH = (stageSize.height / 2) / zoom;
101→        const bufferWorld = 500 / zoom;
102→        return {
103→            minX: camera.x - halfW - bufferWorld,
104→            maxX: camera.x + halfW + bufferWorld,
105→            minY: camera.y - halfH - bufferWorld,
106→            maxY: camera.y + halfH + bufferWorld,
107→        };
108→    }, [camera, stageSize, zoom]);
109→
110→    const visiblePosts = useMemo(() => {
111→        if (!visibleBounds) return posts; // fallback: render all
112→        return posts.filter(post => {
113→            const pos = computedStarPositions.get(post.id);
114→            if (!pos) return true; // keep if no position computed yet
115→            return pos.x >= visibleBounds.minX && pos.x <= visibleBounds.maxX
116→                && pos.y >= visibleBounds.minY && pos.y <= visibleBounds.maxY;
117→        });
118→    }, [posts, computedStarPositions, visibleBounds]);
119→
120→    const bridgePairs = useMemo(() => {
121→        const maxPairs = 120;
122→
123→        if (useEmbeddingBridges) {
124→            const bridgePosts = (activePostIds instanceof Set && activePostIds.size > 0)
125→                ? posts.filter((post) => activePostIds.has(post?.id))
126→                : posts;
127→            return computeSemanticBridges(bridgePosts, computedStarPositions, 0.9, maxPairs);
128→        }
129→
130→        if (!Array.isArray(similarPairs) || similarPairs.length === 0) return [];
131→
132→        return similarPairs
133→            .filter((pair) => Number(pair?.similarity) > 0.9)
134→            .filter((pair) => {
135→                if (!(activePostIds instanceof Set) || activePostIds.size === 0) return true;
136→                return activePostIds.has(pair?.post_a) && activePostIds.has(pair?.post_b);
137→            })
138→            .slice(0, maxPairs);
139→    }, [useEmbeddingBridges, activePostIds, posts, computedStarPositions, similarPairs]);
140→
141→    const hasFocus = focusedStarIds != null;
142→    const dimOpacity = hasFocus ? 0.06 : 1;
143→
144→    return (
145→        <Layer {...layerProps}>
146→            {/* Semantic bridges between similar posts */}
147→            {bridgePairs.length > 0 && (
148→                <Shape
149→                    opacity={dimOpacity}
150→                    sceneFunc={(ctx) => {
151→                        for (const pair of bridgePairs) {
152→                            const posA = computedStarPositions.get(pair.post_a);
153→                            const posB = computedStarPositions.get(pair.post_b);
154→                            if (!posA || !posB) continue;
155→
156→                            const dx = posB.x - posA.x;
157→                            const dy = posB.y - posA.y;
158→                            const dist = Math.sqrt(dx * dx + dy * dy) || 1;
159→
160→                            const mx = (posA.x + posB.x) / 2;
161→                            const my = (posA.y + posB.y) / 2;
162→                            const perpX = (-dy / dist) * dist * 0.06;
163→                            const perpY = (dx / dist) * dist * 0.06;
164→
165→                            ctx.strokeStyle = 'rgba(150,200,255,0.1)';
166→                            ctx.lineWidth = 0.8;
167→                            ctx.shadowColor = 'rgba(150,200,255,0.3)';
168→                            ctx.shadowBlur = 4;
169→                            ctx.beginPath();
170→                            ctx.moveTo(posA.x, posA.y);
171→                            ctx.quadraticCurveTo(mx + perpX, my + perpY, posB.x, posB.y);
172→                            ctx.stroke();
173→                        }
174→                        ctx.shadowBlur = 0;
175→                    }}
176→                    perfectDrawEnabled={false}
177→                    listening={false}
178→                />
179→            )}
180→            {/* Spiral galaxy visuals + connection lines */}
181→            <Shape
182→                opacity={dimOpacity}
183→                sceneFunc={(ctx) => { drawGalaxyVisuals(ctx, galaxyVisuals, galaxyEdges, galaxyUserIdMap); }}
184→                perfectDrawEnabled={false}
185→                listening={false}
186→            />
187→            {/* Galaxy name labels */}
188→            {galaxies?.map((g) => (
189→                <GalaxyLabel
190→                    key={g.userId}
191→                    x={g.x}
192→                    y={g.y}
193→                    name={g.name}
194→                    zoom={zoom}
195→                    onClick={() => onGalaxyClick(g)}
196→                />
197→            ))}
198→            {/* Stars (viewport-culled) */}
199→            {visiblePosts.map((post) => {
200→                const postUserId = post.users?.id ?? post.user_id;
201→                const color = getStarColor(postUserId);
202→                const likeCount = post.like_count != null
203→                    ? post.like_count
204→                    : (Array.isArray(post.likes) && post.likes[0]?.count != null ? post.likes[0].count : 0);
205→                const radius = getStarRadius(likeCount);
206→
207→                const pos = computedStarPositions.get(post.id);
208→                const x = pos?.x ?? post.universe_x ?? post.display_x;
209→                const y = pos?.y ?? post.universe_y ?? post.display_y;
210→
211→                const constellationColor = constellationStarColors?.get(post.id) || null;
212→                const isFocused = focusedStarIds?.has(post.id) || false;
213→                const isDimmed = hasFocus && !isFocused;
214→
215→                return (
216→                    <StarGroup
217→                        key={post.id}
218→                        x={x}
219→                        y={y}
220→                        radius={radius}
221→                        color={color}
222→                        title={post.title}
223→                        showTitle={showTitles}
224→                        isPulsing={pulsingId === post.id}
225→                        onClick={() => onStarClick(post)}
226→                        constellationColor={constellationColor}
227→                        isFocused={isFocused}
228→                        isDimmed={isDimmed}
229→                    />
230→                );
231→            })}
232→        </Layer>
233→    );
234→});
235→
236→InteractiveLayer.displayName = 'InteractiveLayer';
237→
238→export default InteractiveLayer;
