  1→import React, { useRef, useEffect, useCallback } from 'react';
  2→import { getStarColor } from '../utils/starUtils';
  3→import styles from '../Universe.module.css';
  4→
  5→const MINIMAP_SIZE = 160;
  6→const WORLD_MIN = -25000;
  7→const WORLD_MAX = 25000;
  8→const WORLD_RANGE = WORLD_MAX - WORLD_MIN;
  9→
 10→/** Convert world coordinate to minimap pixel */
 11→const worldToMinimap = (val) =>
 12→    ((val - WORLD_MIN) / WORLD_RANGE) * MINIMAP_SIZE;
 13→
 14→/** Convert minimap pixel to world coordinate */
 15→const minimapToWorld = (px) =>
 16→    (px / MINIMAP_SIZE) * WORLD_RANGE + WORLD_MIN;
 17→
 18→const clamp = (value, min, max) => Math.max(min, Math.min(max, value));
 19→
 20→const UniverseMinimap = React.memo(({ galaxies, camera, zoom, stageSize, onNavigate, constellations, computedStarPositions, focusedConstellationId }) => {
 21→    const canvasRef = useRef(null);
 22→    const pointerStateRef = useRef({
 23→        active: false,
 24→        pointerId: null,
 25→        moved: false,
 26→        startX: 0,
 27→        startY: 0,
 28→    });
 29→
 30→    useEffect(() => {
 31→        const canvas = canvasRef.current;
 32→        if (!canvas) return;
 33→
 34→        const ctx = canvas.getContext('2d');
 35→        const dpr = window.devicePixelRatio || 1;
 36→
 37→        canvas.width = MINIMAP_SIZE * dpr;
 38→        canvas.height = MINIMAP_SIZE * dpr;
 39→        ctx.scale(dpr, dpr);
 40→
 41→        // Background
 42→        ctx.fillStyle = 'rgba(10, 14, 26, 0.85)';
 43→        ctx.fillRect(0, 0, MINIMAP_SIZE, MINIMAP_SIZE);
 44→
 45→        // Galaxy dots
 46→        if (galaxies) {
 47→            for (const g of galaxies) {
 48→                const mx = worldToMinimap(g.x);
 49→                const my = worldToMinimap(g.y);
 50→
 51→                ctx.fillStyle = getStarColor(g.userId);
 52→                ctx.globalAlpha = 0.7;
 53→                ctx.beginPath();
 54→                ctx.arc(mx, my, 1.5, 0, Math.PI * 2);
 55→                ctx.fill();
 56→            }
 57→        }
 58→
 59→        ctx.globalAlpha = 1;
 60→
 61→        // Constellation lines
 62→        if (Array.isArray(constellations) && constellations.length > 0 && computedStarPositions) {
 63→            for (const link of constellations) {
 64→                const posA = computedStarPositions.get(link.star_id_a);
 65→                const posB = computedStarPositions.get(link.star_id_b);
 66→                if (!posA || !posB) continue;
 67→
 68→                const ax = worldToMinimap(posA.x);
 69→                const ay = worldToMinimap(posA.y);
 70→                const bx = worldToMinimap(posB.x);
 71→                const by = worldToMinimap(posB.y);
 72→
 73→                const isFocused = focusedConstellationId === link.id;
 74→
 75→                if (isFocused) {
 76→                    // Glow layer
 77→                    ctx.save();
 78→                    ctx.strokeStyle = 'rgba(95, 146, 255, 0.6)';
 79→                    ctx.lineWidth = 3;
 80→                    ctx.globalAlpha = 0.5;
 81→                    ctx.shadowColor = 'rgba(95, 146, 255, 0.9)';
 82→                    ctx.shadowBlur = 8;
 83→                    ctx.beginPath();
 84→                    ctx.moveTo(ax, ay);
 85→                    ctx.lineTo(bx, by);
 86→                    ctx.stroke();
 87→                    ctx.restore();
 88→                    // Bright core
 89→                    ctx.save();
 90→                    ctx.strokeStyle = 'rgba(180, 210, 255, 0.9)';
 91→                    ctx.lineWidth = 1;
 92→                    ctx.globalAlpha = 1;
 93→                    ctx.beginPath();
 94→                    ctx.moveTo(ax, ay);
 95→                    ctx.lineTo(bx, by);
 96→                    ctx.stroke();
 97→                    ctx.restore();
 98→                } else {
 99→                    ctx.strokeStyle = 'rgba(95, 146, 255, 0.4)';
100→                    ctx.lineWidth = 0.5;
101→                    ctx.globalAlpha = focusedConstellationId ? 0.15 : 0.6;
102→                    ctx.beginPath();
103→                    ctx.moveTo(ax, ay);
104→                    ctx.lineTo(bx, by);
105→                    ctx.stroke();
106→                }
107→            }
108→            ctx.globalAlpha = 1;
109→        }
110→
111→        // Viewport rectangle
112→        if (camera && stageSize) {
113→            // Camera is the world-space center, zoom determines how much world is visible
114→            const viewWidth = stageSize.width / zoom;
115→            const viewHeight = stageSize.height / zoom;
116→
117→            const vpLeft = worldToMinimap(camera.x - viewWidth / 2);
118→            const vpTop = worldToMinimap(camera.y - viewHeight / 2);
119→            const vpW = (viewWidth / WORLD_RANGE) * MINIMAP_SIZE;
120→            const vpH = (viewHeight / WORLD_RANGE) * MINIMAP_SIZE;
121→
122→            ctx.strokeStyle = 'rgba(255, 255, 255, 0.6)';
123→            ctx.lineWidth = 1;
124→            ctx.strokeRect(vpLeft, vpTop, vpW, vpH);
125→        }
126→
127→        // Border
128→        ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)';
129→        ctx.lineWidth = 1;
130→        ctx.strokeRect(0, 0, MINIMAP_SIZE, MINIMAP_SIZE);
131→
132→    }, [galaxies, camera, zoom, stageSize, constellations, computedStarPositions, focusedConstellationId]);
133→
134→    const navigateFromClientPoint = useCallback((clientX, clientY, mode = 'fly') => {
135→        const canvas = canvasRef.current;
136→        if (!canvas || !onNavigate) return;
137→
138→        const rect = canvas.getBoundingClientRect();
139→        if (!rect.width || !rect.height) return;
140→
141→        const scaleX = MINIMAP_SIZE / rect.width;
142→        const scaleY = MINIMAP_SIZE / rect.height;
143→
144→        const px = clamp((clientX - rect.left) * scaleX, 0, MINIMAP_SIZE);
145→        const py = clamp((clientY - rect.top) * scaleY, 0, MINIMAP_SIZE);
146→
147→        const worldX = minimapToWorld(px);
148→        const worldY = minimapToWorld(py);
149→
150→        onNavigate(worldX, worldY, mode);
151→    }, [onNavigate]);
152→
153→    const handlePointerDown = useCallback((e) => {
154→        const canvas = canvasRef.current;
155→        if (!canvas) return;
156→
157→        e.preventDefault();
158→        e.stopPropagation();
159→
160→        pointerStateRef.current = {
161→            active: true,
162→            pointerId: e.pointerId,
163→            moved: false,
164→            startX: e.clientX,
165→            startY: e.clientY,
166→        };
167→
168→        if (canvas.setPointerCapture) {
169→            canvas.setPointerCapture(e.pointerId);
170→        }
171→    }, []);
172→
173→    const handlePointerMove = useCallback((e) => {
174→        const state = pointerStateRef.current;
175→        if (!state.active || state.pointerId !== e.pointerId) return;
176→
177→        e.preventDefault();
178→        e.stopPropagation();
179→
180→        const movedEnough = Math.hypot(e.clientX - state.startX, e.clientY - state.startY) > 2;
181→        if (!movedEnough && !state.moved) return;
182→
183→        state.moved = true;
184→        navigateFromClientPoint(e.clientX, e.clientY, 'drag');
185→    }, [navigateFromClientPoint]);
186→
187→    const finishPointer = useCallback((e) => {
188→        const state = pointerStateRef.current;
189→        if (!state.active || state.pointerId !== e.pointerId) return;
190→
191→        e.preventDefault();
192→        e.stopPropagation();
193→
194→        if (state.moved) {
195→            navigateFromClientPoint(e.clientX, e.clientY, 'drag');
196→        } else {
197→            navigateFromClientPoint(e.clientX, e.clientY, 'fly');
198→        }
199→
200→        const canvas = canvasRef.current;
201→        if (canvas?.releasePointerCapture) {
202→            canvas.releasePointerCapture(e.pointerId);
203→        }
204→
205→        pointerStateRef.current = {
206→            active: false,
207→            pointerId: null,
208→            moved: false,
209→            startX: 0,
210→            startY: 0,
211→        };
212→    }, [navigateFromClientPoint]);
213→
214→    const handleContextMenu = useCallback((e) => {
215→        e.preventDefault();
216→    }, []);
217→
218→    return (
219→        <canvas
220→            ref={canvasRef}
221→            className={styles.minimap}
222→            width={MINIMAP_SIZE}
223→            height={MINIMAP_SIZE}
224→            onPointerDown={handlePointerDown}
225→            onPointerMove={handlePointerMove}
226→            onPointerUp={finishPointer}
227→            onPointerCancel={finishPointer}
228→            onPointerLeave={finishPointer}
229→            onContextMenu={handleContextMenu}
230→            title="Click to fly, drag to pan"
231→        />
232→    );
233→});
234→
235→UniverseMinimap.displayName = 'UniverseMinimap';
236→
237→export default UniverseMinimap;
