        worldX: post.universe_x ?? post.display_x,
        worldY: post.universe_y ?? post.display_y,
        z: MIN_Z + rng() * (MAX_Z - MIN_Z),
        color,
        colorRgb: rgb,
        radius: getStarRadius(likeCount),
        title: post.title || '',
        authorName: post.users?.name ?? post.user_name ?? 'Anonymous',
