### 2. New File: `client/src/components/Universe/layers/RocketLayer.jsx`

**Purpose**: Single Konva `<Layer>` with a single `<Shape>` using `sceneFunc` for batch canvas rendering. No individual Konva node components.

**Pattern reference**: Follows the exact pattern from `WormholeLayer.jsx` (lines 226-241) and `DeepSpaceLayer.jsx` (lines 24-37) -- a single `<Shape>` with `sceneFunc`, `perfectDrawEnabled={false}`, `listening={false}`.

```jsx
import React from 'react';
import { Layer, Shape } from 'react-konva';

const TWO_PI = Math.PI * 2;

const RocketLayer = React.memo(({ rocketMode }) => {
    const {
        layerRef, starsRef, sortedIndicesRef, rocketPos,
        heading, velocity, targetIndexRef, screenCenter,
        project, getSpeedRatio, MAX_SPEED,
    } = rocketMode;

    return (
        <Layer ref={layerRef} listening={false}>
            <Shape
                sceneFunc={(ctx) => {
                    const stars = starsRef.current;
                    const sorted = sortedIndicesRef.current;
                    const cx = screenCenter.current.x;
                    const cy = screenCenter.current.y;
                    const speedRatio = Math.abs(velocity.current) / MAX_SPEED;
                    const targetIdx = targetIndexRef.current;

                    // -- Speed lines (behind stars) --
                    if (speedRatio > 0.4) {
                        const lineAlpha = (speedRatio - 0.4) / 0.6; // 0..1
                        ctx.strokeStyle = `rgba(180,210,255,${lineAlpha * 0.3})`;
                        ctx.lineWidth = 1;
                        for (let i = 0; i < 30; i++) {
                            const angle = (i / 30) * TWO_PI;
                            const innerR = 50 + speedRatio * 80;
                            const outerR = innerR + speedRatio * 300;
                            ctx.beginPath();
                            ctx.moveTo(
                                cx + Math.cos(angle) * innerR,
                                cy + Math.sin(angle) * innerR
                            );
                            ctx.lineTo(
                                cx + Math.cos(angle) * outerR,
                                cy + Math.sin(angle) * outerR
                            );
                            ctx.stroke();
                        }
                    }

                    // -- Stars: painter's algorithm (far first) --
                    for (let si = 0; si < sorted.length; si++) {
                        const idx = sorted[si];
                        const star = stars[idx];
                        if (!star) continue;

                        const { projX, projY, scale } = project(star, cx, cy);

                        // Viewport culling
                        if (projX < -200 || projX > cx * 2 + 200 ||
                            projY < -200 || projY > cy * 2 + 200) continue;

                        const baseR = star.radius * scale * 40; // amplify for visibility
                        if (baseR < 0.3) continue; // too small

                        // Hyper-jump distortion
                        const stretchX = 1 + speedRatio * 2.5;
                        const opacity = Math.max(0.1, 1 - speedRatio * 0.6);

                        const { r, g, b } = star.colorRgb;
                        const drawR = Math.min(baseR, 30); // cap radius

                        ctx.save();
                        ctx.translate(projX, projY);
                        ctx.scale(stretchX, 1); // horizontal stretch

                        // Outer glow
                        const glowR = drawR * 3;
                        const glow = ctx.createRadialGradient(0, 0, 0, 0, 0, glowR);
                        glow.addColorStop(0, `rgba(${r},${g},${b},${0.5 * opacity})`);
                        glow.addColorStop(0.4, `rgba(${r},${g},${b},${0.15 * opacity})`);
                        glow.addColorStop(1, `rgba(${r},${g},${b},0)`);
                        ctx.beginPath();
                        ctx.arc(0, 0, glowR, 0, TWO_PI);
                        ctx.fillStyle = glow;
                        ctx.fill();

                        // Core
                        ctx.beginPath();
                        ctx.arc(0, 0, drawR * 0.4, 0, TWO_PI);
                        ctx.fillStyle = `rgba(255,255,255,${0.9 * opacity})`;
                        ctx.fill();

                        ctx.restore();

                        // Targeting bracket (not stretched)
                        if (idx === targetIdx) {
                            const bracketSize = Math.max(drawR * stretchX * 4, 18);
                            const half = bracketSize / 2;
                            const corner = bracketSize * 0.3;
                            const time = performance.now();
                            const pulse = 0.6 + 0.4 * Math.sin(time * 0.004);

                            ctx.strokeStyle = `rgba(100,220,255,${pulse})`;
                            ctx.lineWidth = 1.5;
                            ctx.setLineDash([4, 3]);

                            // Top-left corner
                            ctx.beginPath();
                            ctx.moveTo(projX - half, projY - half + corner);
                            ctx.lineTo(projX - half, projY - half);
                            ctx.lineTo(projX - half + corner, projY - half);
                            ctx.stroke();

                            // Top-right corner
                            ctx.beginPath();
                            ctx.moveTo(projX + half - corner, projY - half);
                            ctx.lineTo(projX + half, projY - half);
                            ctx.lineTo(projX + half, projY - half + corner);
                            ctx.stroke();

                            // Bottom-left corner
                            ctx.beginPath();
                            ctx.moveTo(projX - half, projY + half - corner);
                            ctx.lineTo(projX - half, projY + half);
                            ctx.lineTo(projX - half + corner, projY + half);
                            ctx.stroke();

                            // Bottom-right corner
                            ctx.beginPath();
                            ctx.moveTo(projX + half - corner, projY + half);
                            ctx.lineTo(projX + half, projY + half);
                            ctx.lineTo(projX + half, projY + half - corner);
                            ctx.stroke();

                            ctx.setLineDash([]);
                        }
                    }
                }}
                perfectDrawEnabled={false}
                listening={false}
            />
        </Layer>
    );
});

RocketLayer.displayName = 'RocketLayer';

export default RocketLayer;
```

