### 3. New File: `client/src/components/Universe/components/RocketHUD.jsx`

**Purpose**: Pure HTML overlay (not Konva). Reads from the hook's refs via a low-frequency `useState` updater (10 Hz, not 60fps) to display HUD information.

```jsx
import React, { useEffect, useState, useCallback } from 'react';
import styles from '../Universe.module.css';

const HUD_UPDATE_MS = 100; // 10 Hz for HUD text updates

const RocketHUD = ({ rocketMode, onExit, onInteract }) => {
    const [hudState, setHudState] = useState({
        speed: 0,
        speedRatio: 0,
        targetName: null,
        targetAuthor: null,
    });

    useEffect(() => {
        const interval = setInterval(() => {
            const speedRatio = rocketMode.getSpeedRatio();
            const target = rocketMode.getTargetedPost();
            setHudState({
                speed: Math.abs(rocketMode.velocity.current).toFixed(1),
                speedRatio,
                targetName: target?.title || null,
                targetAuthor: target?.users?.name ?? target?.user_name ?? null,
            });
        }, HUD_UPDATE_MS);

        return () => clearInterval(interval);
    }, [rocketMode]);

    // Enter/Space to interact with targeted star
    useEffect(() => {
        const handleKey = (e) => {
            if (e.key === 'Enter' || e.key === ' ') {
                e.preventDefault();
                onInteract();
            }
            if (e.key === 'Escape') {
                onExit();
            }
        };
        window.addEventListener('keydown', handleKey);
        return () => window.removeEventListener('keydown', handleKey);
    }, [onInteract, onExit]);

    const barWidth = `${Math.min(hudState.speedRatio * 100, 100)}%`;

    return (
        <div className={styles.rocketHud}>
            {/* Speed indicator */}
            <div className={styles.rocketSpeedBar}>
                <div className={styles.rocketSpeedLabel}>SPEED</div>
                <div className={styles.rocketSpeedTrack}>
                    <div
                        className={styles.rocketSpeedFill}
                        style={{ width: barWidth }}
                    />
                </div>
                <div className={styles.rocketSpeedValue}>{hudState.speed}</div>
            </div>

            {/* Targeted star info */}
            {hudState.targetName && (
                <div className={styles.rocketTarget}>
                    <div className={styles.rocketTargetName}>{hudState.targetName}</div>
                    {hudState.targetAuthor && (
                        <div className={styles.rocketTargetAuthor}>by {hudState.targetAuthor}</div>
                    )}
                    <div className={styles.rocketTargetPrompt}>Press ENTER to read</div>
                </div>
            )}

            {/* Controls hint */}
            <div className={styles.rocketControls}>
                <span>W/S Throttle</span>
                <span>A/D Turn</span>
                <span>ENTER Read</span>
                <span>ESC Exit</span>
            </div>

            {/* Exit button */}
            <button className={styles.rocketExitBtn} onClick={onExit}>
                Exit Rocket Mode
            </button>
        </div>
    );
};

export default RocketHUD;
```

